class Subject:
    def __init__(self):
        self._obs = []
    def attach(self, o):
        self._obs.append(o)
    def notify(self, m):
        for o in self._obs:
            o.update(m)

class Observer:
    def __init__(self, name):
        self.name = name
    def update(self, m):
        print(f"{self.name}: {m}")

s = Subject()
s.attach(Observer("X"))
s.attach(Observer("Y"))
s.notify("hi")
